# ❌ ANTI-PATTERN: Fixed batching regardless of queue state
class NaiveInferenceServer:
    def process_requests(self, requests):
        # Always wait for exactly 32 requests before processing
        while len(self.queue) < 32:
            time.sleep(0.1)  # Wasteful polling
        batch = self.queue[:32]
        return self.model.batch_generate(batch)

# ✅ BEST PRACTICE: Adaptive batching with timeout and queue awareness
class ProductionInferenceServer:
    def __init__(self, min_batch=2, max_batch=128, timeout_ms=50):
        self.min_batch = min_batch
        self.max_batch = max_batch
        self.timeout_ms = timeout_ms
        self.queue_arrival_time = {}

    def process_requests(self, requests):
        """Cricket field strategy: aggressive when queue builds, defensive when sparse"""
        batch_size = min(self.max_batch, max(self.min_batch, len(requests)))

        # Timeout check: if oldest request waiting > 50ms, process immediately
        if requests:
            oldest_wait = time.time() - self.queue_arrival_time.get(requests[0]['id'], time.time())
            if oldest_wait > self.timeout_ms / 1000:
                batch_size = len(requests)  # Process all pending

        # Use KV-cache optimized decoding for small batches
        if batch_size <= 4:
            return self.model.stream_generate(
                requests[:batch_size],
                use_speculative_decoding=True,
                cache_strategy='sliding_window'
            )
        # Use aggressive batching for larger queues
        else:
            return self.model.batch_generate(
                requests[:batch_size],
                use_flash_attention=True,
                cache_strategy='full'
            )
